<?php require_once __DIR__.'/../app/poster.php'; $msg=''; $class='notice'; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); try{ if(isset($_POST['regen'])) set_setting('cron_token',bin2hex(random_bytes(32))); if(isset($_POST['interval'])) set_setting('cron_interval_minutes',(string)max(1,(int)$_POST['interval'])); if(isset($_POST['rss'])) {$r=fetch_all_feeds();$msg='RSS取得完了: 成功 '.$r['ok'].'件 / 失敗 '.$r['ng'].'件（'.date('Y-m-d H:i:s').'）'; set_setting('last_rss_cron',date('Y-m-d H:i:s'));} if(isset($_POST['post'])) {$id=run_post();$msg='投稿処理完了: 履歴ID '.$id.'（'.date('Y-m-d H:i:s').'）'; set_setting('last_post_cron',date('Y-m-d H:i:s'));} if(isset($_POST['regen'])) $msg='Web実行用秘密トークンを再生成しました。'; }catch(Throwable $e){$class='notice error';$msg='エラー: 処理に失敗しました。詳細はログを確認してください。'; log_event('error','手動Cron失敗',$e->getMessage());}} admin_header('Cron設定'); if($msg)echo'<p class="'.e($class).'">'.e($msg).'</p>'; $php=PHP_BINARY?:'php'; $token=ensure_cron_token(); echo'<form method=post><input type=hidden name=csrf value='.csrf_token().'><label>実行間隔(分)<input name=interval value="'.e(setting('cron_interval_minutes',60)).'"></label><button>保存</button><button name=rss value=1>RSS取得実行</button><button name=post value=1>livedoor投稿実行</button><button name=regen value=1 class=danger>Webトークン再生成</button></form><div class=card><h3>Cron設定例</h3><p>CLI RSS取得: <code>'.$php.' '.APP_ROOT.'/cron/fetch.php</code></p><p>CLI 投稿: <code>'.$php.' '.APP_ROOT.'/cron/post.php</code></p><p>Web RSS取得: <input readonly value="'.e(app_absolute_url('/cron/fetch.php?token='.$token)).'"></p><p>Web 投稿: <input readonly value="'.e(app_absolute_url('/cron/post.php?token='.$token)).'"></p><p class=muted>Web実行は秘密トークン必須です。ログには完全なトークンを出力しません。CLI実行ではトークン不要です。多重実行はファイルロックで防止します。</p><p>最終RSS実行: '.e(setting('last_rss_cron','-')).'</p><p>最終投稿実行: '.e(setting('last_post_cron','-')).'</p></div>'; admin_footer();
